public class BasicMethods {

    // void method - performs action, returns nothing
    public static void greet(String name) {
        System.out.println("Hello, " + name + "!");
    }

    // method that returns an int
    public static int add(int a, int b) {
        return a + b;
    }

    // method with no parameters
    public static void printLine() {
        System.out.println("--------------------");
    }

    public static void main(String[] args) {
        greet("Alice");
        printLine();
        int result = add(10, 25);
        System.out.println("Sum: " + result);
        printLine();
        greet("Bob");
    }
}

public class Calculator {
    private String brand;

    public Calculator(String brand) {
        this.brand = brand;
    }

    // Overloaded add methods
    public int add(int a, int b) {
        return a + b;
    }

    public double add(double a, double b) {
        return a + b;
    }

    public int add(int a, int b, int c) {
        return a + b + c;
    }

    // Instance method accessing instance variable
    public String getBrand() {
        return this.brand;
    }

    // Static utility method
    public static int multiply(int a, int b) {
        return a * b;
    }

    public static void main(String[] args) {
        Calculator calc = new Calculator("ScientificPro");
        System.out.println("Brand: " + calc.getBrand());
        System.out.println("add(int, int): " + calc.add(5, 3));
        System.out.println("add(double, double): " + calc.add(5.5, 3.2));
        System.out.println("add(int, int, int): " + calc.add(5, 3, 2));
        System.out.println("multiply (static): " + Calculator.multiply(4, 7));
    }
}

public class AdvancedMethods {

    // Recursive method to calculate factorial
    public static long factorial(int n) {
        if (n < 0) throw new IllegalArgumentException("n must be non-negative");
        if (n == 0 || n == 1) return 1; // base case
        return n * factorial(n - 1);   // recursive call
    }

    // Recursive Fibonacci
    public static int fibonacci(int n) {
        if (n <= 1) return n;
        return fibonacci(n - 1) + fibonacci(n - 2);
    }

    // Varargs method
    public static double average(double... numbers) {
        if (numbers.length == 0) return 0;
        double sum = 0;
        for (double num : numbers) sum += num;
        return sum / numbers.length;
    }

    public static void main(String[] args) {
        System.out.println("5! = " + factorial(5));
        System.out.println("10! = " + factorial(10));
        System.out.println();
        System.out.print("Fibonacci sequence: ");
        for (int i = 0; i < 8; i++) {
            System.out.print(fibonacci(i) + " ");
        }
        System.out.println();
        System.out.println();
        System.out.println("avg(10, 20): " + average(10, 20));
        System.out.println("avg(1,2,3,4,5): " + average(1, 2, 3, 4, 5));
        System.out.println("avg(no args): " + average());
    }
}

public class Employee {
    private String name;
    private String department;
    private double baseSalary;
    private int yearsOfService;

    public Employee(String name, String department, double baseSalary, int yearsOfService) {
        this.name = name;
        this.department = department;
        this.baseSalary = baseSalary;
        this.yearsOfService = yearsOfService;
    }

    // Calculate annual bonus based on years of service
    public double calculateBonus() {
        if (yearsOfService >= 10) return baseSalary * 0.20;
        else if (yearsOfService >= 5) return baseSalary * 0.10;
        else return baseSalary * 0.05;
    }

    // Calculate tax deduction (simplified)
    public double calculateTax() {
        double grossSalary = baseSalary + calculateBonus();
        if (grossSalary > 100000) return grossSalary * 0.30;
        else if (grossSalary > 50000) return grossSalary * 0.20;
        else return grossSalary * 0.10;
    }

    // Net salary after tax and bonus
    public double calculateNetSalary() {
        return (baseSalary + calculateBonus()) - calculateTax();
    }

    // Generate payslip as formatted string
    public String generatePayslip() {
        return String.format(
            "=== PAYSLIP ===\nEmployee: %s\nDepartment: %s\nBase Salary: $%.2f\nBonus: $%.2f\nTax: $%.2f\nNET SALARY: $%.2f\n==============",
            name, department, baseSalary, calculateBonus(), calculateTax(), calculateNetSalary()
        );
    }

    // Static method for department-level summary
    public static void printSummary(Employee[] employees) {
        System.out.println("--- Department Summary ---");
        double total = 0;
        for (Employee e : employees) {
            total += e.calculateNetSalary();
        }
        System.out.printf("Total Net Payroll: $%.2f%n", total);
    }

    public static void main(String[] args) {
        Employee emp1 = new Employee("Alice Johnson", "Engineering", 80000, 8);
        Employee emp2 = new Employee("Bob Smith", "Marketing", 45000, 2);

        System.out.println(emp1.generatePayslip());
        System.out.println();
        System.out.println(emp2.generatePayslip());
        System.out.println();
        printSummary(new Employee[]{emp1, emp2});
    }
}

