public class PerfectNumbers {
    public static boolean isPerfect(int n) {
        if (n <= 1) return false;
        int sum = 1;
        for (int i = 2; i <= Math.sqrt(n); i++) {
            if (n % i == 0) {
                sum += i;
                if (i != n / i) sum += n / i;
            }
        }
        return sum == n;
    }

    public static void main(String[] args) {
        System.out.println("Perfect numbers between 1 and 10000:");
        for (int i = 1; i <= 10000; i++) {
            if (isPerfect(i)) System.out.println(i);
        }
    }
}

public class StringUtils {
    // Count occurrences of a char
    public static int count(String str, char ch) {
        int cnt = 0;
        for (char c : str.toCharArray()) {
            if (c == ch) cnt++;
        }
        return cnt;
    }

    // Count occurrences of a substring
    public static int count(String str, String sub) {
        if (sub.isEmpty()) return 0;
        int cnt = 0;
        int idx = 0;
        while ((idx = str.indexOf(sub, idx)) != -1) {
            cnt++;
            idx += sub.length();
        }
        return cnt;
    }

    // Count words in a string
    public static int count(String str) {
        if (str == null || str.trim().isEmpty()) return 0;
        return str.trim().split("\\s+").length;
    }

    public static void main(String[] args) {
        String text = "hello world, hello java world";
        System.out.println("Char 'l' count: " + count(text, 'l'));
        System.out.println("Substring 'hello' count: " + count(text, "hello"));
        System.out.println("Word count: " + count(text));
    }
}

